INSERT INTO recipe (id, name, description, image_url, cooking_time, difficulty, servings, calories, protein, fat, carbs, taste_tags, health_tags, target_goals, steps, status, created_by) VALUES
(1, '鸡胸肉西兰花轻食碗', '低脂高蛋白轻食碗，适合减脂期控制热量。', '/images/recipes/pexels-recipe-01-chicken-broccoli-bowl.jpg', 25, 'EASY', 1, 420, 35.00, 9.00, 45.00, '清淡,轻食', '低脂,高蛋白,低卡', 'FAT_LOSS,MUSCLE_GAIN', '["鸡胸肉切块并用少量生抽和黑胡椒腌制。","西兰花焯水，玉米煮熟。","鸡胸肉煎熟后与蔬菜装盘。","按口味加少量盐和柠檬汁。"]', 1, 2),
(2, '虾仁豆腐蔬菜汤', '虾仁、豆腐和青菜搭配，热量低且蛋白质充足。', '/images/recipes/pexels-recipe-02-shrimp-tofu-vegetable-soup.jpg', 20, 'EASY', 1, 330, 28.00, 10.00, 22.00, '清淡,汤类', '低卡,高蛋白,少油', 'FAT_LOSS,BALANCED', '["虾仁洗净，豆腐切块。","锅中加水煮开后放入豆腐和青菜。","加入虾仁煮至变色。","用盐和葱调味。"]', 1, 2),
(3, '番茄鸡蛋燕麦粥', '番茄鸡蛋与燕麦组合，快手且饱腹。', '/images/recipes/pexels-recipe-03-tomato-egg-oatmeal.jpg', 15, 'EASY', 1, 360, 20.00, 11.00, 42.00, '清淡,快手', '低卡,饱腹,营养均衡', 'FAT_LOSS,BALANCED', '["番茄切块，鸡蛋打散。","燕麦加水煮软。","放入番茄煮出汤汁。","倒入蛋液并搅拌成蛋花。"]', 1, 2),
(4, '金枪鱼生菜沙拉', '金枪鱼搭配生菜和鸡蛋，适合作为低脂高蛋白餐。', '/images/recipes/pexels-recipe-04-tuna-egg-salad-bowl.jpg', 10, 'EASY', 1, 390, 32.00, 14.00, 25.00, '清爽,沙拉', '低脂,高蛋白,快手', 'FAT_LOSS,MUSCLE_GAIN', '["生菜洗净沥干。","鸡蛋煮熟切块。","金枪鱼沥去多余水分。","混合后加入少量柠檬汁和黑胡椒。"]', 1, 2),
(5, '香煎鳕鱼配芦笋', '鳕鱼和芦笋搭配，脂肪低，口味清爽。', '/images/recipes/pexels-recipe-05-cod-asparagus-plate.jpg', 25, 'MEDIUM', 1, 410, 34.00, 13.00, 28.00, '清淡,西式', '低脂,高蛋白', 'FAT_LOSS,BALANCED', '["鳕鱼用盐、黑胡椒和柠檬汁腌制。","芦笋洗净切段。","平底锅加少量橄榄油煎鳕鱼。","芦笋煎熟后一起装盘。"]', 1, 2),
(6, '鸡蛋豆腐蒸羹', '鸡蛋和豆腐蒸制，口感软嫩，适合轻食。', '/images/recipes/pexels-recipe-06-egg-tofu-custard.jpg', 18, 'EASY', 1, 300, 22.00, 16.00, 12.00, '清淡,家常', '低卡,易做,高蛋白', 'FAT_LOSS,BALANCED', '["鸡蛋打散后加温水。","豆腐切小块放入碗中。","倒入蛋液并盖上保鲜膜。","上锅蒸熟后撒葱花。"]', 1, 2),
(7, '番茄炒蛋', '经典家常菜，做法简单，适合日常均衡饮食。', '/images/recipes/pexels-recipe-07-tomato-scrambled-egg.jpg', 15, 'EASY', 1, 320, 18.00, 16.00, 20.00, '家常,清淡', '快手,营养均衡', 'BALANCED', '["番茄切块，鸡蛋打散。","先炒鸡蛋至凝固后盛出。","番茄炒出汁后加入鸡蛋。","加盐调味后出锅。"]', 1, 2),
(8, '土豆胡萝卜炖牛肉', '牛肉、土豆和胡萝卜炖煮，饱腹且营养均衡。', '/images/recipes/pexels-recipe-08-beef-potato-carrot-stew.jpg', 60, 'MEDIUM', 2, 680, 35.00, 28.00, 65.00, '家常,炖菜', '均衡,饱腹', 'BALANCED,MUSCLE_GAIN', '["牛肉焯水备用。","土豆和胡萝卜切块。","牛肉加水炖煮至变软。","加入蔬菜继续炖熟并调味。"]', 1, 2),
(9, '香菇青菜豆腐饭', '香菇、青菜和豆腐搭配米饭，适合均衡素食。', '/images/recipes/pexels-recipe-09-mushroom-tofu-rice.jpg', 25, 'EASY', 1, 520, 22.00, 14.00, 78.00, '家常,素食', '均衡,清淡', 'BALANCED', '["香菇切片，青菜洗净。","豆腐煎至微黄。","香菇和青菜翻炒调味。","搭配米饭装盘。"]', 1, 2),
(10, '三文鱼藜麦饭', '三文鱼、藜麦和西兰花组合，提供优质脂肪和蛋白质。', '/images/recipes/pexels-recipe-10-salmon-poke-quinoa-bowl.jpg', 35, 'MEDIUM', 1, 620, 36.00, 24.00, 58.00, '清淡,西式', '均衡,高蛋白,优质脂肪', 'BALANCED,MUSCLE_GAIN', '["藜麦煮熟备用。","三文鱼用黑胡椒和盐腌制。","三文鱼煎熟，西兰花焯水。","全部装入碗中并加柠檬汁。"]', 1, 2),
(11, '宫保鸡丁轻油版', '减少用油的家常宫保鸡丁，保留风味并控制热量。', '/images/recipes/pexels-recipe-11-kungpao-chicken-light.jpg', 25, 'MEDIUM', 1, 580, 32.00, 24.00, 52.00, '家常,下饭', '适中热量,高蛋白', 'BALANCED,MUSCLE_GAIN', '["鸡胸肉切丁腌制。","黄瓜切丁，花生备用。","少油炒熟鸡丁。","加入黄瓜和花生快速翻炒。"]', 1, 2),
(12, '紫菜虾皮鸡蛋汤面', '汤面做法快，紫菜、虾皮和鸡蛋补充蛋白质。', '/images/recipes/pexels-recipe-12-seaweed-egg-noodle-soup.jpg', 15, 'EASY', 1, 500, 24.00, 14.00, 70.00, '快手,汤面', '均衡,补钙', 'BALANCED', '["面条煮熟。","另起锅加水煮紫菜和虾皮。","打入鸡蛋形成蛋花。","加入面条并调味。"]', 1, 2),
(13, '黑椒牛肉糙米饭', '牛肉搭配糙米和西兰花，适合增肌期补充能量。', '/images/recipes/pexels-recipe-13-bulgogi-beef-rice-bowl.jpg', 35, 'MEDIUM', 1, 720, 45.00, 24.00, 78.00, '黑椒,便当', '高蛋白,增肌,饱腹', 'MUSCLE_GAIN', '["糙米提前煮熟。","牛肉切片用黑胡椒和生抽腌制。","西兰花焯水。","牛肉炒熟后与糙米和西兰花装盘。"]', 1, 2),
(14, '鸡胸肉牛油果卷饼', '鸡胸肉和牛油果卷入全麦饼，适合作为增肌便当。', '/images/recipes/pexels-recipe-14-chicken-avocado-wrap.jpg', 20, 'EASY', 1, 650, 42.00, 24.00, 62.00, '便当,西式', '高蛋白,增肌,便携', 'MUSCLE_GAIN', '["鸡胸肉煎熟切条。","牛油果压成泥。","全麦饼加热。","加入鸡胸肉、生菜和牛油果卷起。"]', 1, 2),
(15, '煎蛋牛肉藜麦碗', '牛肉、鸡蛋和藜麦提供高蛋白和优质碳水。', '/images/recipes/pexels-recipe-15-beef-egg-quinoa-bowl.jpg', 30, 'MEDIUM', 1, 760, 48.00, 28.00, 76.00, '训练后,碗餐', '高蛋白,增肌,均衡', 'MUSCLE_GAIN', '["藜麦煮熟备用。","牛肉煎熟切片。","鸡蛋煎至喜欢的熟度。","搭配蔬菜一起装碗。"]', 1, 2),
(16, '豆腐鸡肉蛋白餐', '豆腐、鸡胸肉和鸡蛋组合，蛋白质密度高。', '/images/recipes/pexels-recipe-16-tofu-broccoli-protein-bowl.jpg', 25, 'EASY', 1, 610, 46.00, 22.00, 46.00, '清淡,蛋白餐', '高蛋白,低脂,增肌', 'MUSCLE_GAIN,FAT_LOSS', '["鸡胸肉切片煎熟。","豆腐切块煎香。","鸡蛋煮熟或煎熟。","全部装盘并用少量生抽调味。"]', 1, 2),
(17, '金枪鱼玉米全麦三明治', '金枪鱼、玉米和全麦面包组合，快手便携。', '/images/recipes/pexels-recipe-17-tuna-corn-sandwich.jpg', 10, 'EASY', 1, 590, 40.00, 18.00, 68.00, '快手,便携', '高蛋白,增肌', 'MUSCLE_GAIN,BALANCED', '["金枪鱼沥干。","玉米煮熟。","全麦面包夹入金枪鱼、生菜和玉米。","按口味加入黑胡椒。"]', 1, 2),
(18, '虾仁鸡蛋炒意面', '虾仁、鸡蛋和意面搭配，适合训练后补充蛋白质和碳水。', '/images/recipes/pexels-recipe-18-shrimp-egg-pasta.jpg', 25, 'EASY', 1, 700, 43.00, 22.00, 82.00, '训练后,主食', '高蛋白,增肌,快手', 'MUSCLE_GAIN', '["意面煮熟备用。","虾仁炒至变色。","加入鸡蛋炒散。","放入意面和少量生抽翻炒。"]', 1, 2),
(19, '冬瓜虾仁汤', '冬瓜和虾仁煮成清淡汤品，热量低且适合晚餐。', '/images/recipes/pexels-recipe-19-shrimp-winter-melon-soup.jpg', 18, 'EASY', 1, 260, 24.00, 5.00, 24.00, '清淡,汤类', '低卡,高蛋白,少油', 'FAT_LOSS,BALANCED', '["冬瓜去皮切片，虾仁洗净。","锅中加水煮开后放入冬瓜。","冬瓜变软后加入虾仁煮至变色。","用盐、姜和葱调味后出锅。"]', 1, 2),
(20, '菠菜鸡蛋豆腐汤', '菠菜、鸡蛋和豆腐搭配，清淡快手又有蛋白质。', '/images/recipes/pexels-recipe-20-spinach-egg-tofu-soup.jpg', 15, 'EASY', 1, 290, 23.00, 14.00, 16.00, '清淡,快手', '低卡,高蛋白,易做', 'FAT_LOSS,BALANCED', '["菠菜洗净切段，豆腐切块。","锅中加水煮开后放入豆腐。","加入菠菜煮软。","倒入蛋液形成蛋花并调味。"]', 1, 2),
(21, '巴沙鱼西兰花轻食盘', '巴沙鱼和西兰花组成低脂轻食盘，适合控制热量。', '/images/recipes/pexels-recipe-21-fish-broccoli-plate.jpg', 22, 'EASY', 1, 380, 34.00, 8.00, 38.00, '清淡,轻食', '低脂,高蛋白,低卡', 'FAT_LOSS', '["巴沙鱼用柠檬汁、盐和黑胡椒腌制。","西兰花焯水备用。","平底锅少油煎熟巴沙鱼。","搭配米饭和西兰花装盘。"]', 1, 2),
(22, '鸡腿肉南瓜沙拉', '去皮鸡腿肉搭配南瓜和生菜，兼顾饱腹与清爽。', '/images/recipes/pexels-recipe-22-chicken-salad-bowl.jpg', 25, 'EASY', 1, 430, 31.00, 14.00, 45.00, '清爽,轻食', '高蛋白,饱腹,适中热量', 'FAT_LOSS,BALANCED', '["鸡腿肉去皮切块并煎熟。","南瓜蒸熟切块。","生菜洗净沥干。","全部混合后加少量醋和黑胡椒。"]', 1, 2),
(23, '番茄豆腐菌菇汤', '番茄、豆腐和菌菇煮汤，酸甜清淡，适合轻食。', '/images/recipes/pexels-recipe-23-tomato-tofu-mushroom-soup.jpg', 18, 'EASY', 1, 310, 20.00, 12.00, 28.00, '清淡,汤类', '低卡,均衡,素食', 'FAT_LOSS,BALANCED', '["番茄切块，豆腐切块，菌菇洗净。","番茄先煮出汤汁。","加入豆腐和菌菇煮熟。","用盐和葱调味。"]', 1, 2),
(24, '西葫芦鸡胸肉炒蛋', '西葫芦、鸡胸肉和鸡蛋快炒，蛋白质充足且少油。', '/images/recipes/pexels-recipe-24-zucchini-chicken-egg.jpg', 18, 'EASY', 1, 390, 36.00, 15.00, 24.00, '家常,快手', '低脂,高蛋白,低卡', 'FAT_LOSS,MUSCLE_GAIN', '["鸡胸肉切片腌制。","西葫芦切片，鸡蛋打散。","先炒鸡蛋后盛出。","鸡胸肉和西葫芦炒熟后加入鸡蛋调味。"]', 1, 2),
(25, '紫薯酸奶轻食碗', '紫薯和无糖酸奶搭配，适合作为轻量早餐。', '/images/recipes/pexels-recipe-25-sweet-potato-yogurt-bowl.jpg', 12, 'EASY', 1, 340, 13.00, 6.00, 60.00, '清爽,早餐', '饱腹,低脂,快手', 'FAT_LOSS,BALANCED', '["紫薯蒸熟切块。","碗中加入无糖酸奶。","放入紫薯和少量玉米粒。","按口味加入少量燕麦增加饱腹感。"]', 1, 2),
(26, '黄瓜虾仁鸡蛋杯', '黄瓜、虾仁和鸡蛋做成快手轻食杯。', '/images/recipes/pexels-recipe-26-cucumber-shrimp-egg-cup.jpg', 12, 'EASY', 1, 320, 29.00, 14.00, 18.00, '清爽,快手', '低卡,高蛋白,少油', 'FAT_LOSS', '["虾仁煮熟，鸡蛋煮熟切块。","黄瓜切丁。","将虾仁、鸡蛋和黄瓜放入碗中。","加入少量柠檬汁和黑胡椒拌匀。"]', 1, 2),
(27, '白菜豆腐鸡肉汤', '白菜、豆腐和鸡胸肉煮汤，清淡又有饱腹感。', '/images/recipes/pexels-recipe-27-cabbage-tofu-chicken-soup.jpg', 22, 'EASY', 1, 360, 34.00, 11.00, 24.00, '清淡,汤类', '低脂,高蛋白,饱腹', 'FAT_LOSS,BALANCED', '["白菜洗净切段，豆腐切块。","鸡胸肉切片并焯水。","锅中加水煮白菜和豆腐。","加入鸡胸肉煮熟并调味。"]', 1, 2),
(28, '洋葱彩椒牛肉饭', '洋葱和彩椒搭配牛肉和米饭，适合日常均衡午餐。', '/images/recipes/pexels-recipe-28-bibimbap-beef-rice-bowl.jpg', 25, 'EASY', 1, 620, 36.00, 20.00, 72.00, '家常,下饭', '均衡,高蛋白', 'BALANCED,MUSCLE_GAIN', '["牛肉切片用生抽和黑胡椒腌制。","洋葱和彩椒切条。","牛肉炒熟后加入蔬菜翻炒。","搭配米饭装盘。"]', 1, 2),
(29, '香菇鸡腿肉杂粮饭', '鸡腿肉、香菇和杂粮饭组合，适合健康便当。', '/images/recipes/pexels-recipe-29-mushroom-chicken-grain-rice.jpg', 30, 'MEDIUM', 1, 610, 34.00, 18.00, 76.00, '家常,便当', '均衡,饱腹,高蛋白', 'BALANCED', '["鸡腿肉去皮切块腌制。","香菇切片。","鸡腿肉煎熟后加入香菇翻炒。","搭配杂粮饭装入餐盒。"]', 1, 2),
(30, '番茄牛肉荞麦面', '番茄牛肉汤底搭配荞麦面，酸甜开胃。', '/images/recipes/pexels-recipe-30-tomato-beef-soba-noodle.jpg', 25, 'EASY', 1, 560, 32.00, 16.00, 72.00, '汤面,家常', '均衡,高蛋白', 'BALANCED', '["番茄切块煮出汤汁。","牛肉片快速焯熟。","荞麦面煮熟放入碗中。","倒入番茄汤和牛肉片调味。"]', 1, 2),
(31, '南瓜鸡蛋杂粮粥', '南瓜、鸡蛋和杂粮饭煮成温和饱腹粥。', '/images/recipes/pexels-recipe-31-pumpkin-egg-porridge.jpg', 20, 'EASY', 1, 420, 19.00, 10.00, 66.00, '清淡,早餐', '均衡,饱腹,易做', 'BALANCED,FAT_LOSS', '["南瓜切块蒸软。","杂粮饭加水煮开。","加入南瓜压散。","倒入蛋液搅成蛋花并调味。"]', 1, 2),
(32, '西红柿豆腐炖牛肉', '番茄、豆腐和牛肉炖煮，营养均衡。', '/images/recipes/pexels-recipe-32-tomato-tofu-beef-stew.jpg', 35, 'MEDIUM', 2, 640, 40.00, 24.00, 58.00, '家常,炖菜', '均衡,高蛋白', 'BALANCED,MUSCLE_GAIN', '["牛肉切块焯水。","番茄炒出汤汁。","加入牛肉炖煮至变软。","放入豆腐继续炖熟。"]', 1, 2),
(33, '白菜猪里脊炒饭', '白菜和猪里脊搭配米饭，做法快且适合作为一餐。', '/images/recipes/pexels-recipe-33-pork-cabbage-fried-rice.jpg', 20, 'EASY', 1, 590, 30.00, 18.00, 76.00, '家常,快手', '均衡,饱腹', 'BALANCED', '["猪里脊切丝腌制。","白菜切碎。","先炒猪里脊至变色。","加入白菜和米饭翻炒调味。"]', 1, 2),
(34, '菌菇青菜鸡蛋面', '菌菇、青菜和鸡蛋搭配面条，快手均衡。', '/images/recipes/pexels-recipe-34-mushroom-greens-egg-noodle.jpg', 15, 'EASY', 1, 520, 24.00, 15.00, 72.00, '汤面,快手', '均衡,易做', 'BALANCED', '["面条煮熟。","菌菇和青菜煮软。","打入鸡蛋形成蛋花。","加入面条并调味。"]', 1, 2),
(35, '彩椒豆腐鸡肉盖饭', '彩椒、豆腐和鸡肉搭配米饭，颜色丰富且营养均衡。', '/images/recipes/pexels-recipe-35-chicken-kale-rice-bowl.jpg', 25, 'EASY', 1, 600, 38.00, 18.00, 70.00, '家常,盖饭', '均衡,高蛋白', 'BALANCED,MUSCLE_GAIN', '["鸡胸肉切丁腌制。","豆腐和彩椒切块。","鸡肉和豆腐煎香。","加入彩椒翻炒后盖在米饭上。"]', 1, 2),
(36, '玉米鸡蛋牛奶粥', '玉米、鸡蛋和牛奶煮成快手早餐粥。', '/images/recipes/pexels-recipe-36-corn-egg-milk-oatmeal.jpg', 15, 'EASY', 1, 450, 21.00, 14.00, 62.00, '早餐,清淡', '均衡,快手,饱腹', 'BALANCED', '["玉米粒煮熟。","牛奶小火加热。","加入玉米和燕麦煮软。","倒入蛋液搅拌至熟。"]', 1, 2),
(37, '孜然牛肉红薯碗', '牛肉和红薯组合，适合训练后补充蛋白和碳水。', '/images/recipes/pexels-recipe-37-buddha-sweet-potato-bowl.jpg', 30, 'MEDIUM', 1, 720, 44.00, 22.00, 86.00, '训练后,碗餐', '高蛋白,增肌,饱腹', 'MUSCLE_GAIN', '["红薯蒸熟切块。","牛肉切片用孜然粉和生抽腌制。","牛肉煎熟。","搭配红薯和蔬菜装碗。"]', 1, 2),
(38, '鸡腿排杂粮饭', '去皮鸡腿排搭配杂粮饭，适合增肌便当。', '/images/recipes/pexels-recipe-38-chicken-thigh-grain-rice.jpg', 30, 'MEDIUM', 1, 700, 42.00, 24.00, 78.00, '便当,家常', '高蛋白,增肌,饱腹', 'MUSCLE_GAIN,BALANCED', '["鸡腿肉去皮拍平腌制。","杂粮饭提前煮熟。","鸡腿排煎熟切块。","搭配西兰花和杂粮饭装盘。"]', 1, 2),
(39, '虾仁牛油果荞麦面', '虾仁、牛油果和荞麦面组合，适合训练后轻负担补给。', '/images/recipes/pexels-recipe-39-shrimp-avocado-salad.jpg', 22, 'EASY', 1, 650, 38.00, 22.00, 76.00, '训练后,清爽', '高蛋白,增肌,均衡', 'MUSCLE_GAIN,BALANCED', '["荞麦面煮熟过凉。","虾仁煮熟。","牛油果切片。","将荞麦面、虾仁和牛油果拌匀调味。"]', 1, 2),
(40, '猪里脊鸡蛋蛋白餐', '猪里脊和鸡蛋组成高蛋白餐，适合增肌期。', '/images/recipes/pexels-recipe-40-pork-egg-protein-plate.jpg', 25, 'EASY', 1, 640, 48.00, 24.00, 52.00, '蛋白餐,家常', '高蛋白,增肌', 'MUSCLE_GAIN', '["猪里脊切片腌制。","鸡蛋煮熟或煎熟。","猪里脊煎熟。","搭配米饭和青菜装盘。"]', 1, 2),
(41, '牛肉毛豆藜麦饭', '牛肉、毛豆和藜麦提供蛋白质与优质碳水。', '/images/recipes/pexels-recipe-41-quinoa-chicken-bowl.jpg', 30, 'MEDIUM', 1, 760, 50.00, 24.00, 82.00, '训练后,碗餐', '高蛋白,增肌,均衡', 'MUSCLE_GAIN', '["藜麦煮熟。","毛豆煮熟备用。","牛肉切片煎熟。","全部放入碗中并调味。"]', 1, 2),
(42, '鸡胸肉酸奶全麦卷', '鸡胸肉搭配无糖酸奶和全麦饼，便携高蛋白。', '/images/recipes/pexels-recipe-42-chicken-yogurt-wrap.jpg', 18, 'EASY', 1, 620, 44.00, 16.00, 72.00, '便携,西式', '高蛋白,增肌,快手', 'MUSCLE_GAIN,FAT_LOSS', '["鸡胸肉煎熟切条。","无糖酸奶加少量黑胡椒调成酱。","全麦饼加热。","放入鸡胸肉、生菜和酸奶酱后卷起。"]', 1, 2),
(43, '巴沙鱼红薯训练餐', '巴沙鱼和红薯搭配，脂肪较低且适合训练餐。', '/images/recipes/pexels-recipe-43-fish-sweet-potato-plate.jpg', 25, 'EASY', 1, 610, 42.00, 10.00, 86.00, '训练后,轻食', '高蛋白,低脂,增肌', 'MUSCLE_GAIN,FAT_LOSS', '["红薯蒸熟切块。","巴沙鱼用盐和黑胡椒腌制。","巴沙鱼煎熟。","搭配西兰花和红薯装盘。"]', 1, 2),
(44, '双蛋牛肉杂粮饭', '牛肉和双蛋搭配杂粮饭，蛋白质充足。', '/images/recipes/pexels-recipe-44-beef-double-egg-rice.jpg', 25, 'EASY', 1, 780, 52.00, 28.00, 82.00, '训练后,便当', '高蛋白,增肌,饱腹', 'MUSCLE_GAIN', '["杂粮饭加热。","牛肉切片煎熟。","两个鸡蛋煎熟。","将牛肉、鸡蛋和杂粮饭装盘。"]', 1, 2),
(45, '虾仁豆腐高蛋白盖饭', '虾仁和豆腐搭配米饭，口味清淡且蛋白质充足。', '/images/recipes/pexels-recipe-45-shrimp-poke-bowl.jpg', 20, 'EASY', 1, 620, 44.00, 18.00, 72.00, '盖饭,清淡', '高蛋白,增肌,均衡', 'MUSCLE_GAIN,BALANCED', '["虾仁炒至变色。","豆腐切块煎香。","加入少量生抽调味。","盖在米饭上并撒葱花。"]', 1, 2);
